import {
  Box,
  Button,
  Flex,
  Grid,
  Select,
  Text,
  Table,
  Thead,
  Tbody,
  Tr,
  Th,
  Td,
  IconButton,
  Heading,
} from "@chakra-ui/react";
import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { EditIcon } from "@chakra-ui/icons";
import { useDispatch, useSelector } from "react-redux";
import { deleteUsers, getUser } from "../../Redux/AdminReducer/action";
import Pagination from "./Pagination";
import AdminNavTop from "../AdminNavTop";

const Users = () => {
  const store = useSelector((store) => store.AdminReducer.users);
  const dispatch = useDispatch();

  const [page, setPage] = useState(1);
  const [search, setSearch] = useState("");
  const [order, setOrder] = useState("");

  const limit = 4;
  const count = 2;

  useEffect(() => {
    dispatch(getUser(page, limit));
  }, [page]);

  const handleDelete = (id, name) => {
    dispatch(deleteUsers(id));
    alert(`${name} deleted`);
  };

  return (
    <Box bg="#f7f9fa" minH="100vh">
      <AdminNavTop handleSearch={(e) => setSearch(e.target.value)} />

      <Box maxW="1200px" mx="auto" p={6}>
        <Heading size="lg" mb={6}>
          Users Management
        </Heading>

        {/* Top controls */}
        <Flex justify="space-between" mb={4} wrap="wrap" gap={3}>
          <Select
            maxW="250px"
            onChange={(e) => setOrder(e.target.value)}
          >
            <option value="">Sort by Age</option>
            <option value="asc">Ascending</option>
            <option value="desc">Descending</option>
          </Select>

          <Link to="/admin/users/add">
            <Button bg="#A435F0" color="white" _hover={{ bg: "#8710d8" }}>
              Create User
            </Button>
          </Link>
        </Flex>

        {/* Table Card */}
        <Box bg="white" borderRadius="lg" boxShadow="sm" overflow="hidden">
          <Table variant="simple">
            <Thead bg="#f7f9fa">
              <Tr>
                <Th>Name</Th>
                <Th>Role</Th>
                <Th>Email</Th>
                <Th>City</Th>
                <Th>Age</Th>
                <Th>Courses</Th>
                <Th>Actions</Th>
              </Tr>
            </Thead>

            <Tbody>
              {store?.map((el) => (
                <Tr key={el._id} _hover={{ bg: "#f9fafb" }}>
                  <Td>{el.name}</Td>
                  <Td>{el.role}</Td>
                  <Td>{el.email}</Td>
                  <Td>{el.city}</Td>
                  <Td>{el.age}</Td>
                  <Td>{el.course.length}</Td>

                  {/* Actions */}
                  <Td>
                    <Flex gap={2}>
                      <Link to={`/admin/users/edit/${el._id}`}>
                        <IconButton
                          icon={<EditIcon />}
                          size="sm"
                          variant="outline"
                        />
                      </Link>

                      <Button
                        size="sm"
                        colorScheme="red"
                        onClick={() => handleDelete(el._id, el.name)}
                      >
                        Delete
                      </Button>
                    </Flex>
                  </Td>
                </Tr>
              ))}
            </Tbody>
          </Table>
        </Box>

        {/* Pagination */}
        <Flex justify="space-between" mt={4}>
          <Button
            onClick={() => setPage((p) => p - 1)}
            isDisabled={page <= 1}
          >
            Prev
          </Button>

          <Pagination
            totalCount={count}
            current_page={page}
            handlePageChange={setPage}
          />

          <Button
            onClick={() => setPage((p) => p + 1)}
            isDisabled={page >= count}
          >
            Next
          </Button>
        </Flex>
      </Box>
    </Box>
  );
};

export default Users;
